<?php
namespace Tests\Feature;
use App\Domain\Characters\Appearance\CharacterAppearanceService;use App\Domain\Media\EquipmentLayers\EquipmentLayerAssetService;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\CharacterTemplate;use App\Models\Item;use App\Models\ItemInstance;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class CharacterAppearanceTest extends TestCase{use RefreshDatabase;private function image(){ $path=tempnam(sys_get_temp_dir(),'layer_');$image=imagecreatetruecolor(512,768);imagealphablending($image,false);imagesavealpha($image,true);imagefill($image,0,0,imagecolorallocatealpha($image,0,0,0,127));imagepng($image,$path);imagedestroy($image);return new UploadedFile($path,'layer.png','image/png',null,true);}public function test_appearance_uses_the_actual_equipped_slot_and_prepared_order(){Storage::fake('public');$template=CharacterTemplate::factory()->create(['body_type'=>'human_neutral_01']);$character=Character::factory()->for(User::factory())->create(['character_template_id'=>$template->id]);$item=Item::create(['code'=>'appearance_ring','name'=>'Anillo visual','item_type'=>'equipment','equipment_type'=>'ring','required_level'=>1,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$layers=app(EquipmentLayerAssetService::class);$left=$layers->replace($item,'human_neutral_01','ring_left',$this->image());$right=$layers->replace($item,'human_neutral_01','ring_right',$this->image());$instance=ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$item->id,'status'=>'equipped']);CharacterEquipment::create(['character_id'=>$character->id,'item_instance_id'=>$instance->id,'slot'=>'ring_right','equipped_at'=>now()]);$appearance=app(CharacterAppearanceService::class)->presentation($character);$this->assertSame('human_neutral_01',$appearance['body_type']);$this->assertSame('ring_right',$appearance['layers'][0]['visual_slot']);$this->assertSame(40,$appearance['layers'][0]['order']);$this->assertSame($right->id,$appearance['layers'][0]['media_asset_id']);$this->assertNotSame($left->id,$appearance['layers'][0]['media_asset_id']);}
public function test_missing_body_type_keeps_base_fallback_and_omits_equipment(){Storage::fake('public');$character=Character::factory()->for(User::factory())->create(['character_template_id'=>null]);$appearance=app(CharacterAppearanceService::class)->presentation($character);$this->assertNull($appearance['body_type']);$this->assertTrue($appearance['fallback_used']);$this->assertSame([],$appearance['layers']);}}
